body.script:
$.getScript('https://cdn.jsdelivr.net/npm/js-cookie@2/src/js.cookie.min.js', function() {
  var cookieName = 'notificationClosed';
  var cookieValue = 'userClosedIt';
  var cookieExpire = Number($('.cookie-expire-number').text());

  if(typeof Cookies.get(cookieName) !== 'undefined') $('.notification-bar-container').remove();
  $('.notification-close').click(function() {
    Cookies.set(cookieName, cookieValue, { expires: cookieExpire });
  });
});

(function () {
  "use strict";

  // ===========================================
  // FusionAuth Marketo Form Handler v3.0.0
  // ===========================================

  // ===========================================
  // CONFIG
  // ===========================================
  var MARKETO = {
    munchkinId: "195-ZDI-012",
    baseUrl: "//195-ZDI-012.mktoweb.com",
    pdfBaseUrl: "https://hello.fusionauth.io/rs/195-ZDI-012/images/",
  };

  // ===========================================
  // PAGE TYPE DETECTION
  // ===========================================
  // Determines thank-you behavior based on URL path.
  // Pages not matching any rule get default thank-you.
  // "native" types let Marketo handle submission.
  var PAGE_TYPES = [
    { prefix: "/ebooks/",      type: "download" },
    { prefix: "/tech-papers/", type: "download" },
    { prefix: "/contact",      type: "contact" },
    { prefix: "/webinar/",     type: "webinar" },
    { prefix: "/lp/",          type: "lp" },
  ];

  function getPageType() {
    var path = window.location.pathname.replace(/\/+$/, "");
    for (var i = 0; i < PAGE_TYPES.length; i++) {
      if (path.indexOf(PAGE_TYPES[i].prefix) === 0) {
        return {
          type: PAGE_TYPES[i].type,
          slug: path.replace(PAGE_TYPES[i].prefix, ""),
        };
      }
    }
    return { type: "default", slug: "" };
  }

  // ===========================================
  // THANK-YOU MESSAGES
  // ===========================================
  var MESSAGES = {
    download: {
      heading: "Thank you for your interest!",
      body: "You can find the resource here:",
      showLink: true,
      footnote: "A copy has also been sent to you via email.
If you can\u2019t find it in your inbox, please check your spam or junk mail.",
    },
    webinar: {
      heading: "You\u2019re registered!",
      body: "You\u2019re signed up for {{assetName}}. Check your email for confirmation and calendar details.",
      showLink: false,
      footnote: "",
    },
    contact: {
      redirect: "/thank-you-final",
      redirectParams: ["Email", "FirstName", "LastName"],
    },
    lp: {
      native: true,
    },
    default: {
      heading: "Thank you!",
      body: "Your submission has been received.",
      showLink: false,
      footnote: "",
    },
  };

  function buildThankYou(msg, assetName, downloadUrl) {
    var linkText = msg.linkLabel || assetName || "Download";
    var heading = (msg.heading || "").replace(/\{\{assetName\}\}/g, assetName);
    var body = (msg.body || "").replace(/\{\{assetName\}\}/g, assetName);
    var footnote = msg.footnote ? msg.footnote.replace(/\{\{assetName\}\}/g, assetName) : "";

    var html =
      '
' +
      '
' + heading + "" +
      '
' + body + "";

    if (msg.showLink && downloadUrl) {
      html += '' + linkText + "";
    }
    if (footnote) {
      html += '
' + footnote + "";
    }
    html += "";
    return html;
  }

  // ===========================================
  // JSON SANITIZE
  // ===========================================
  function sanitizeFormValues(form) {
    var vals = form.getValues();
    var cleaned = {};
    var changed = false;
    Object.keys(vals).forEach(function (key) {
      if (typeof vals[key] === "string") {
        var v = JSON.stringify(vals[key]).slice(1, -1);
        if (v !== vals[key]) {
          cleaned[key] = v;
          changed = true;
        }
      }
    });
    if (changed) form.setValues(cleaned);
  }

  // ===========================================
  // WAIT FOR MKTOFORMS2
  // ===========================================
  function waitForForms2(callback) {
    if (typeof MktoForms2 !== "undefined") { callback(); return; }
    var attempts = 0;
    var poll = setInterval(function () {
      attempts++;
      if (typeof MktoForms2 !== "undefined") { clearInterval(poll); callback(); }
      else if (attempts > 50) { clearInterval(poll); }
    }, 200);
  }

  // ===========================================
  // MAIN — runs for any page with a mktoForm_ element
  // ===========================================
  function run() {
    // Find any Marketo form on the page (excludes newsletter)
    var formEl = document.querySelector('form[id^="mktoForm_"]');
    if (!formEl) return;

    var match = formEl.id.match(/mktoForm_(\d+)/);
    if (!match) return;

    var formId = parseInt(match[1], 10);
    var page = getPageType();
    var msg = MESSAGES[page.type] || MESSAGES.default;

    // Build download URL for ebook/tech-paper pages
    var downloadUrl = "";
    if (page.type === "download" && page.slug) {
      downloadUrl = MARKETO.pdfBaseUrl + page.slug + ".pdf";
    }

    // Asset name from h1
    var h1 = document.querySelector("h1");
    var assetName = h1 ? h1.textContent.trim() : "";

    // Wrap in card if not inside an existing styled container
    var inContainer = formEl.closest(".contact-us_form-div") || formEl.closest(".hubspot-embed-form-div");
    if (!inContainer && !formEl.closest(".fa-mkto-card")) {
      var card = document.createElement("div");
      card.className = "fa-mkto-card";
      formEl.parentNode.insertBefore(card, formEl);
      card.appendChild(formEl);
    }

    waitForForms2(function () {
      MktoForms2.loadForm(MARKETO.baseUrl, MARKETO.munchkinId, formId);

      MktoForms2.whenReady(function (form) {
        if (form.getId() !== formId) return;

        // Fix inline widths on radio lists
        formEl.querySelectorAll(".mktoRadioList").forEach(function (el) {
          el.style.width = "100%";
        });

        // Sanitize on submit
        form.onSubmit(function () { sanitizeFormValues(form); });

        // Native: let Marketo handle submission
        if (msg.native) return;

        form.onSuccess(function (values) {
          // Redirect type
          if (msg.redirect) {
            var params = [];
            if (msg.redirectParams) {
              msg.redirectParams.forEach(function (field) {
                var val = values[field] || "";
                params.push(encodeURIComponent(field.toLowerCase()) + "=" + encodeURIComponent(val));
              });
            }
            window.location.href = msg.redirect + (params.length ? "?" + params.join("&") : "");
            return false;
          }

          // Inline thank-you
          var cardEl = formEl.closest(".fa-mkto-card");
          var tyHtml = buildThankYou(msg, assetName, downloadUrl);

          if (cardEl) {
            cardEl.innerHTML = tyHtml;
          } else {
            var ty = document.createElement("div");
            ty.innerHTML = tyHtml;
            formEl.parentNode.replaceChild(ty, formEl);
          }

          return false;
        });
      });
    });
  }

  // ===========================================
  // FOOTER NEWSLETTER
  // ===========================================
  var NEWSLETTER = {
    formId: 1057,
    targetSelector: "#mkto-newsletter",
    thankYou: {
      heading: "You\u2019re subscribed!",
      body: "Thanks for signing up. Keep an eye on your inbox for the latest from FusionAuth.",
    },
  };

  function runNewsletter() {
    var target = document.querySelector(NEWSLETTER.targetSelector);
    if (!target) return;

    var formEl = document.createElement("form");
    formEl.id = "mktoForm_" + NEWSLETTER.formId;
    target.appendChild(formEl);

    waitForForms2(function () {
      MktoForms2.loadForm(MARKETO.baseUrl, MARKETO.munchkinId, NEWSLETTER.formId);

      MktoForms2.whenReady(function (form) {
        if (form.getId() !== NEWSLETTER.formId) return;

        form.onSubmit(function () { sanitizeFormValues(form); });

        form.onSuccess(function () {
          target.innerHTML =
            '
' +
            '
' + NEWSLETTER.thankYou.heading + '' +
            '
' + NEWSLETTER.thankYou.body + '' +
            '';
          return false;
        });
      });
    });
  }

  // ===========================================
  // RUN
  // ===========================================
  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", function () { run(); runNewsletter(); });
  } else {
    run();
    runNewsletter();
  }
})();
